function turnOnSoundForAd() {
    SGHelper.musicChanel.soundTransform.volume = 1;
    SGHelper.musicChanel.enable();
}

function turnOffSoundForAd() {
    SGHelper.musicChanel.soundTransform.volume = 0;
    SGHelper.musicChanel.disable();
}

